#!/bin/bash
set -e
echo "🚀 Starting full deploy..."
mkdir -p /root/btbot/logs /root/ps1trade/logs
pip3 install python-binance requests pandas numpy ta python-dotenv --break-system-packages -q
echo "✅ Packages installed"

echo "📝 Writing btbot files..."
printf "%s" "" | base64 -d > /root/btbot/main.py
printf "%s" "" | base64 -d > /root/btbot/bot_engine.py
printf "%s" "" | base64 -d > /root/btbot/config.py
printf "%s" "" | base64 -d > /root/btbot/strategy.py
printf "%s" "" | base64 -d > /root/btbot/market_filter.py
printf "%s" "" | base64 -d > /root/btbot/state_manager.py
printf "%s" "" | base64 -d > /root/btbot/telegram_notify.py
printf "%s" "" | base64 -d > /root/btbot/logger.py
printf "%s" "" | base64 -d > /root/btbot/.env
echo "✅ btbot files done"

echo "📝 Writing ps1trade files..."
printf "%s" "" | base64 -d > /root/ps1trade/main.py
printf "%s" "" | base64 -d > /root/ps1trade/bot_engine.py
printf "%s" "" | base64 -d > /root/ps1trade/config.py
printf "%s" "" | base64 -d > /root/ps1trade/strategy.py
printf "%s" "" | base64 -d > /root/ps1trade/market_filter.py
printf "%s" "" | base64 -d > /root/ps1trade/state_manager.py
printf "%s" "" | base64 -d > /root/ps1trade/telegram_notify.py
printf "%s" "" | base64 -d > /root/ps1trade/logger.py
printf "%s" "" | base64 -d > /root/ps1trade/.env
echo "✅ ps1trade files done"

cat > /etc/systemd/system/btbot.service << SVC
[Unit]
Description=btbot - Binance Live Trading Bot
After=network-online.target
[Service]
Type=simple
User=root
WorkingDirectory=/root/btbot
ExecStart=/usr/bin/python3 /root/btbot/main.py
Restart=on-failure
RestartSec=30
Environment=PYTHONUNBUFFERED=1
StandardOutput=journal
StandardError=journal
[Install]
WantedBy=multi-user.target
SVC

cat > /etc/systemd/system/ps1trade.service << SVC2
[Unit]
Description=ps1trade - Binance Paper Trading Bot
After=network-online.target
[Service]
Type=simple
User=root
WorkingDirectory=/root/ps1trade
ExecStart=/usr/bin/python3 /root/ps1trade/main.py
Restart=on-failure
RestartSec=30
Environment=PYTHONUNBUFFERED=1
StandardOutput=journal
StandardError=journal
[Install]
WantedBy=multi-user.target
SVC2

systemctl daemon-reload
systemctl stop btbot ps1trade 2>/dev/null || true
sleep 1
systemctl enable btbot ps1trade
systemctl start btbot ps1trade
sleep 5
echo ""
echo "═══════════════════════════════"
echo "  STATUS"
echo "═══════════════════════════════"
systemctl status btbot --no-pager | head -12
echo ""
systemctl status ps1trade --no-pager | head -12
echo ""
journalctl -u btbot -n 25 --no-pager
echo ""
echo "✅ Deploy complete!"
echo "Watch: journalctl -u btbot -f"